<?php require_once '../config/db.php'; require_once '../includes/auth.php'; require_admin(); $page_title='Subscriptions'; if(isset($_GET['delete'])){mysqli_query($conn,'DELETE FROM SUBSCRIPTION WHERE subscription_id='.intval($_GET['delete'])); header('Location: subscriptions.php'); exit();} if($_SERVER['REQUEST_METHOD']==='POST'){ $stmt=mysqli_prepare($conn,'INSERT INTO SUBSCRIPTION(member_id,plan_id,start_date,end_date,subscription_status,discount_percent) VALUES(?,?,?,?,?,?)'); mysqli_stmt_bind_param($stmt,'iisssd',$_POST['member_id'],$_POST['plan_id'],$_POST['start_date'],$_POST['end_date'],$_POST['subscription_status'],$_POST['discount_percent']); mysqli_stmt_execute($stmt); header('Location: subscriptions.php'); exit(); } $members=mysqli_query($conn,"SELECT m.person_id, CONCAT(p.first_name,' ',p.last_name) name FROM MEMBER m JOIN PERSON p ON m.person_id=p.person_id"); $plans=mysqli_query($conn,'SELECT plan_id, plan_name FROM MEMBERSHIP_PLAN'); $result=mysqli_query($conn,"SELECT s.subscription_id, CONCAT(p.first_name,' ',p.last_name) member_name, mp.plan_name, s.start_date, s.end_date, s.subscription_status, s.discount_percent FROM SUBSCRIPTION s JOIN MEMBER m ON s.member_id=m.person_id JOIN PERSON p ON m.person_id=p.person_id JOIN MEMBERSHIP_PLAN mp ON s.plan_id=mp.plan_id ORDER BY s.subscription_id DESC"); require_once '../includes/header.php'; require_once '../includes/sidebar.php'; ?>
<div class="card form-card"><h2>Add Subscription</h2><form method="POST" class="form-grid"><div><label>Member</label><select name="member_id"><?php while($m=mysqli_fetch_assoc($members)): ?><option value="<?= $m['person_id'] ?>"><?= safe($m['name']) ?></option><?php endwhile; ?></select></div><div><label>Plan</label><select name="plan_id"><?php while($p=mysqli_fetch_assoc($plans)): ?><option value="<?= $p['plan_id'] ?>"><?= safe($p['plan_name']) ?></option><?php endwhile; ?></select></div><div><label>Start</label><input class="input" type="date" name="start_date" required></div><div><label>End</label><input class="input" type="date" name="end_date" required></div><div><label>Status</label><select name="subscription_status"><option>Pending</option><option>Active</option><option>Expired</option><option>Cancelled</option></select></div><div><label>Discount %</label><input class="input" type="number" step="0.01" name="discount_percent" value="0"></div><div class="full"><button class="btn">Add Subscription</button></div></form></div><h2 class="section-title">Subscriptions</h2><div class="table-wrap"><table><tr><th>ID</th><th>Member</th><th>Plan</th><th>Start</th><th>End</th><th>Status</th><th>Discount</th><th>Action</th></tr><?php while($r=mysqli_fetch_assoc($result)): ?><tr><td><?= safe($r['subscription_id']) ?></td><td><?= safe($r['member_name']) ?></td><td><?= safe($r['plan_name']) ?></td><td><?= safe($r['start_date']) ?></td><td><?= safe($r['end_date']) ?></td><td><span class="badge"><?= safe($r['subscription_status']) ?></span></td><td><?= safe($r['discount_percent']) ?>%</td><td><a class="btn btn-danger" onclick="return confirm('Delete subscription?')" href="subscriptions.php?delete=<?= $r['subscription_id'] ?>">Delete</a></td></tr><?php endwhile; ?></table></div><?php require_once '../includes/footer.php'; ?>
